const rawText = typeof $input.first().json.text === 'string' ? $input.first().json.text : '';

// ------------------ Normalize ------------------
const lines = rawText
  .replace(/\r/g, '')
  .split('\n')
  .map(l => (typeof l === 'string' ? l.trim() : ''))
  .filter(l => l.length > 0);

const fullText = lines.join(' ');

// ------------------ Helpers ------------------
function safeExtract(regex) {
  if (!regex || !fullText) return null;
  const m = fullText.match(regex);
  if (!m || !m[1]) return null;
  return String(m[1]).trim();
}

function parseMoney(str) {
  if (!str) return null;
  const num = String(str).replace(/[^0-9.]/g, '');
  const val = Number(num);
  return isNaN(val) ? null : val;
}

// ------------------ Vendor ------------------
let vendorName = null;
let vendorEmail = null;
let vendorPhone = null;
let vendorAddressParts = [];

for (let i = 0; i < lines.length; i++) {
  if (/^INVOICE$/i.test(lines[i])) {
    vendorName = lines[i + 1] || null;
    for (let j = i + 2; j < i + 7; j++) {
      if (!lines[j]) continue;
      if (/Bill to/i.test(lines[j])) break;

      if (lines[j].match(/@/)) vendorEmail = lines[j];
      else if (lines[j].match(/^\+?\d{9,}/)) vendorPhone = lines[j];
      else vendorAddressParts.push(lines[j]);
    }
    break;
  }
}

const vendorAddress = vendorAddressParts.join(', ') || null;

// ------------------ Bill To ------------------
let billToName = null;
let billToAddressParts = [];

const billToIndex = lines.findIndex(l => /^Bill to$/i.test(l));

if (billToIndex >= 0) {
  for (let i = billToIndex + 1; i < lines.length; i++) {
    const line = lines[i];
    if (/^Ship to$/i.test(line)) break;
    if (/^Invoice details$/i.test(line)) break;

    if (!billToName) {
      billToName = line;
    } else {
      billToAddressParts.push(line);
    }
  }
}

const billToAddress = billToAddressParts.join(', ') || null;

// ------------------ Ship To ------------------
let shipToName = null;
let shipToAddressParts = [];

const shipToIndex = lines.findIndex(l => /^Ship to$/i.test(l));

if (shipToIndex >= 0) {
  for (let i = shipToIndex + 1; i < lines.length; i++) {
    const line = lines[i];
    if (/^Invoice details$/i.test(line)) break;

    if (!shipToName) {
      shipToName = line;
    } else {
      shipToAddressParts.push(line);
    }
  }
}

const shipToAddress = shipToAddressParts.join(', ') || null;

// ------------------ Invoice Meta ------------------
const invoiceNumber = safeExtract(/Invoice no\.\s*:?\s*([A-Za-z0-9\-]+)/i);
const terms = safeExtract(/Terms\s*:?\s*([A-Za-z0-9\s]+)/i);
const invoiceDate = safeExtract(/Invoice date\s*:?\s*([0-9\/\-]+)/i);
const dueDate = safeExtract(/Due date\s*:?\s*([0-9\/\-]+)/i);

// ------------------ Totals ------------------
const totalRaw = safeExtract(/Total\s*Ksh\s*([\d,.]+)/i);
const total = parseMoney(totalRaw);

// ------------------ Line Items ------------------
const lineItems = [];

for (let i = 0; i < lines.length; i++) {
  // Example:
  // 1. Customization Tailored to fit 1 Ksh 200.00 Ksh 200.00
  const itemMatch = lines[i].match(
    /^\d+\.\s+(.+?)\s+(\d+)\s+Ksh\s*([\d,.]+)\s+Ksh\s*([\d,.]+)/i
  );

  if (!itemMatch) continue;

  const description = itemMatch[1].trim();
  const quantity = Number(itemMatch[2]);
  const rate = parseMoney(itemMatch[3]);
  const amount = parseMoney(itemMatch[4]);

  if (!isNaN(quantity) && rate !== null && amount !== null) {
    lineItems.push({
      description,
      quantity,
      rate,
      amount,
      currency: 'KES'
    });
  }
}

// ------------------ Final Output ------------------
return [
  {
    json: {
      invoiceNumber,
      invoiceDate,
      dueDate,
      terms,

      total,
      currency: 'KES',

      vendor: {
        name: vendorName,
        address: vendorAddress,
        email: vendorEmail,
        phone: vendorPhone
      },

      billTo: {
        name: billToName,
        address: billToAddress
      },

      shipTo: {
        name: shipToName,
        address: shipToAddress
      },

      lineItems,

      rawText
    }
  }
];
